import anthropic, json, hashlib

client = anthropic.Anthropic()

CHANGE_CLASSIFIER_TOOL = {
    "name": "classify_prompt_change",
    "description": "Classify the tier of a post-sign-off prompt change",
    "input_schema": {
        "type": "object",
        "required": ["tier", "rationale", "affected_spec_items",
                     "re_eval_required", "re_sign_off_required",
                     "approvers_required", "sla_days"],
        "properties": {
            "tier": {"enum": ["minor", "moderate", "major"]},
            "rationale": {"type": "string"},
            "affected_spec_items": {
                "type": "array",
                "description": "IDs of must-do / must-not-do items affected",
                "items": {"type": "string"}
            },
            "re_eval_required": {"type": "boolean"},
            "re_sign_off_required": {"type": "boolean"},
            "approvers_required": {
                "type": "array",
                "items": {"type": "string"}
            },
            "sla_days": {"type": "integer"},
            "risk_notes": {"type": "string"}
        }
    }
}

def classify_prompt_change(old_prompt, new_prompt, behaviour_spec):
    old_hash = hashlib.sha256(old_prompt.encode()).hexdigest()[:8]
    new_hash = hashlib.sha256(new_prompt.encode()).hexdigest()[:8]

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[CHANGE_CLASSIFIER_TOOL],
        tool_choice={"type": "tool", "name": "classify_prompt_change"},
        messages=[{
            "role": "user",
            "content": (
                f"Classify this system prompt change.\n\n"
                f"OLD prompt (hash: {old_hash}):\n{old_prompt}\n\n"
                f"NEW prompt (hash: {new_hash}):\n{new_prompt}\n\n"
                f"Behaviour spec:\n{json.dumps(behaviour_spec, indent=2)}\n\n"
                "Classification rules:\n"
                "- minor: wording/phrasing change only; no must-do/must-not-do item affected\n"
                "- moderate: threshold, condition, or priority order changed; ≥1 spec item affected\n"
                "- major: new must-do added, must-not-do removed or weakened, new output format, new capability\n\n"
                "If in doubt, classify up (never down). Note any must-not-do items weakened."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

