import anthropic, json, hashlib
from datetime import datetime

client = anthropic.Anthropic()

PCR_TOOL = {
    "name": "create_change_record",
    "description": "Create a Prompt Change Record (PCR) for a post-sign-off prompt edit",
    "input_schema": {
        "type": "object",
        "required": ["change_id", "feature_id", "change_date", "author",
                     "tier", "rationale", "old_prompt_hash", "new_prompt_hash",
                     "affected_spec_items", "approvers_required", "sign_off_status"],
        "properties": {
            "change_id": {"type": "string"},
            "feature_id": {"type": "string"},
            "change_date": {"type": "string"},
            "author": {"type": "string"},
            "tier": {"enum": ["minor", "moderate", "major"]},
            "rationale": {"type": "string"},
            "old_prompt_hash": {"type": "string"},
            "new_prompt_hash": {"type": "string"},
            "affected_spec_items": {"type": "array", "items": {"type": "string"}},
            "approvers_required": {"type": "array", "items": {"type": "string"}},
            "approvers": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "role": {"type": "string"},
                        "name": {"type": "string"},
                        "approved_at": {"type": "string"}
                    }
                }
            },
            "sign_off_status": {"enum": ["PENDING", "APPROVED", "REJECTED"]}
        }
    }
}

def create_change_record(
    feature_id, author, old_prompt, new_prompt,
    change_rationale, classification_result, pcr_number
):
    old_hash = hashlib.sha256(old_prompt.encode()).hexdigest()[:8]
    new_hash = hashlib.sha256(new_prompt.encode()).hexdigest()[:8]
    today = datetime.today().strftime("%Y-%m-%d")

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[PCR_TOOL],
        tool_choice={"type": "tool", "name": "create_change_record"},
        messages=[{
            "role": "user",
            "content": (
                f"Create a PCR for feature {feature_id}.\n"
                f"Author: {author}\n"
                f"Date: {today}\n"
                f"Change rationale: {change_rationale}\n"
                f"Old hash: {old_hash}, New hash: {new_hash}\n"
                f"Classification result: {json.dumps(classification_result)}\n"
                f"PCR number: {pcr_number}\n\n"
                "sign_off_status starts as PENDING. "
                "approvers list starts empty — approvers sign it later."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")
